/* ════════════════════════════════════════════════════════════════════════
 * pdf-master-prime.js — Módulo compartilhado para geração de PDF
 * dos simuladores Master Prime (estilo Conkey, layout adaptativo).
 *
 * Uso típico em cada simulador:
 *   <script src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js"></script>
 *   <script src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js"></script>
 *   <script src="pdf-master-prime.js"></script>
 *
 *   PdfMasterPrime.gerar({
 *     tituloEstrategia: 'Operação Simples',
 *     filename: 'master-prime-op-simples',
 *     blocos: [
 *       { tipo: 'card', titulo: 'DADOS DA COTA', linhas: [...] },
 *       { tipo: 'card', titulo: 'DETALHES DA CONTEMPLAÇÃO', linhas: [...] },
 *       { tipo: 'tabela', titulo: 'COMPARATIVO APÓS CONTEMPLAÇÃO', ... }
 *     ]
 *   });
 *
 * Modos suportados:
 *   - PdfMasterPrime.gerar(opt)    → gera e baixa o PDF
 *   - PdfMasterPrime.preview(opt)  → renderiza inline na página (validação visual)
 * ════════════════════════════════════════════════════════════════════════ */
(function () {
  'use strict';

  const PDF_WIDTH = 1300;
  const NAVY = '#2D3F5E';
  const NAVY_DARK = '#1E2D45';
  const CARD_BG = '#F4F5F7';
  const TEXT_MUTED = '#6B7280';
  const BORDER = '#E5E7EB';
  // Tons auxiliares para os novos blocos (tabela-secao destaque, cards-comparativos, etc.)
  const NAVY_SOFT = '#E8ECF3';      // fundo de linha destacada em tabela-secao
  const ZEBRA = '#FAFAFB';          // zebra striping em tabela-ampla / resultado-secao
  const GREEN_BG = '#E8F5EE';       // fundo card "Consórcio" em cards-comparativos
  const GREEN_DARK = '#2F6F4E';     // texto + ícone do lado verde
  const GRAY_BG = '#F4F5F7';        // fundo card "Financiamento" / neutro
  const PURPLE_LIGHT = '#F0EBF7';   // destaque suave (linhas em tabela-secao)
  const PURPLE_BORDER = '#C8B5DC';  // borda de mini-cards destacados

  // ─── Disclaimer padrão ───
  const DISCLAIMER_PADRAO = [
    'Os resultados apresentados nesta simulação possuem caráter meramente informativo e indicativo, sendo elaborados com base em informações fornecidas pelo usuário, as quais podem ser estimadas, hipotéticas ou não refletir condições reais de mercado, não constituindo promessa, garantia ou obrigação de resultado, tampouco vinculando a administradora ou quaisquer terceiros.',
    'A efetiva contratação do consórcio está condicionada à disponibilidade de vagas nos respectivos grupos, à análise e aprovação da administradora, bem como ao integral atendimento dos requisitos, regras e condições estabelecidos no contrato de adesão e na regulamentação aplicável.',
    'O usuário declara estar ciente de que o contrato de adesão, o regulamento do consórcio e os demais documentos aplicáveis constituem os instrumentos que regem a relação contratual, recomendando-se sua leitura integral, sendo o aceite manifestação inequívoca de ciência e concordância com todos os seus termos.'
  ];

  // ─── Logo Master Prime (PNG oficial em base64) ───
  // Usa exatamente o mesmo logo.png do portal. O filter brightness(0) invert(1)
  // deixa o logo todo branco, igual ao sidebar do portal. Embedado em base64
  // pra que o html2canvas consiga renderizar sem CORS / sem dependencia de path.
  const LOGO_DATA_URL = 'data:image/png;base64,';
  const LOGO_HTML = `<img src="${LOGO_DATA_URL}" alt="Master Prime" style="height:64px; width:auto; display:block; filter:brightness(0) invert(1);">`;

  // ─── HEADER ───
  // O logo já contém "Master Prime" + "Corretora de Consórcios e Seguros" embutidos.
  // Não duplicamos esse texto no header.
  function renderHeader(tituloEstrategia) {
    return `
      <div style="background:${NAVY}; color:#fff; padding:24px 50px; display:flex; justify-content:space-between; align-items:center;">
        <div style="display:flex; align-items:center;">
          ${LOGO_HTML}
        </div>
        <div style="font-size:18px; font-weight:600;">Estratégia Simulada: ${tituloEstrategia || ''}</div>
      </div>`;
  }

  // ─── FOOTER ───
  function renderFooter() {
    const hoje = new Date();
    const dd = String(hoje.getDate()).padStart(2, '0');
    const mm = String(hoje.getMonth() + 1).padStart(2, '0');
    const yyyy = hoje.getFullYear();
    return `
      <div style="background:${NAVY}; color:#fff; padding:22px 50px; display:flex; justify-content:space-between; align-items:center; font-size:15px;">
        <div style="font-weight:600;">Master Prime · Simulador de Consórcio</div>
        <div style="text-align:right; line-height:1.5;">Documento gerado em ${dd}/${mm}/${yyyy}<br>Página 1/1</div>
      </div>`;
  }

  // ─── BLOCO TIPO "CARD" ───
  // {
  //   tipo: 'card',
  //   titulo: 'DADOS DA COTA',
  //   linhas: [
  //     { campos: [{label, value}, ...], destaque: {label, value, multi: [{label, value}]} },
  //     { campos: [{label, value}, ...] }    // linha 2 (sem destaque)
  //   ]
  // }
  function renderCard(bloco) {
    const linhasHtml = (bloco.linhas || []).map((linha, idxLinha) => {
      const campos = (linha.campos || []).filter(c => c && c.value !== undefined && c.value !== null && c.value !== '');
      if (campos.length === 0 && !linha.destaque) return '';

      // Quantas colunas?
      let nCols = campos.length;
      const hasDestaque = !!linha.destaque;

      // Linha 1 normalmente tem destaque (parcela inicial / crédito disponível) à direita
      const cellsHtml = campos.map(c => `
        <div>
          <div style="font-size:13px; color:${TEXT_MUTED}; margin-bottom:6px;">${c.label}</div>
          <div style="font-size:18px; font-weight:600;">${c.value}</div>
        </div>`).join('');

      let destaqueHtml = '';
      if (hasDestaque) {
        const d = linha.destaque;
        if (d.multi && Array.isArray(d.multi)) {
          // multiplas badges (ex: "3 parcelas" + "Demais parcelas")
          destaqueHtml = `
            <div style="text-align:right;">
              <div style="display:flex; gap:14px; align-items:flex-end; justify-content:flex-end;">
                ${d.multi.map(m => `
                  <div>
                    <div style="font-size:13px; color:${TEXT_MUTED}; margin-bottom:6px;">${m.label}</div>
                    <div style="background:${NAVY}; color:#fff; font-weight:700; font-size:18px; padding:10px 18px; border-radius:7px; display:inline-block;">${m.value}</div>
                  </div>`).join('')}
              </div>
            </div>`;
        } else {
          destaqueHtml = `
            <div style="text-align:right;">
              <div style="font-size:13px; color:${TEXT_MUTED}; margin-bottom:6px;">${d.label}</div>
              <div style="background:${NAVY}; color:#fff; font-weight:700; font-size:18px; padding:10px 18px; border-radius:7px; display:inline-block;">${d.value}</div>
            </div>`;
        }
      }

      const gridCols = hasDestaque
        ? `repeat(${Math.max(nCols, 1)},1fr) auto`
        : `repeat(${Math.max(nCols, 1)},1fr)`;
      const marginTop = idxLinha === 0 ? '' : 'margin-top:18px;';

      return `
        <div style="display:grid; grid-template-columns:${gridCols}; gap:32px; align-items:center; ${marginTop}">
          ${cellsHtml}
          ${destaqueHtml}
        </div>`;
    }).filter(Boolean).join('');

    return `
      <div style="font-size:14px; font-weight:700; letter-spacing:2.5px; color:${NAVY}; margin:28px 0 16px;">${bloco.titulo}</div>
      <div style="background:${CARD_BG}; border-radius:12px; padding:24px 30px;">
        ${linhasHtml}
      </div>`;
  }

  // ─── BLOCO TIPO "TABELA COMPARATIVA" ───
  // {
  //   tipo: 'tabela',
  //   titulo: 'COMPARATIVO APÓS CONTEMPLAÇÃO',
  //   colunas: ['REDUÇÃO DE PARCELA', 'REDUÇÃO DE PRAZO'],
  //   separador: 'OU',  // opcional, default 'OU'
  //   linhas: [
  //     { label: 'Parcela', valores: ['R$ 1.591,92', 'R$ 2.400,00'] },
  //     { label: 'Prazo restante', valores: ['99 meses', '66 meses'] },
  //     { label: 'CET (Custo Efetivo Total)', valores: ['0,29% ao mês | 3,54% ao ano', '0,43% ao mês | 5,28% ao ano'] }
  //   ]
  // }
  function renderTabela(bloco) {
    const sep = bloco.separador !== undefined ? bloco.separador : 'OU';
    const nCols = (bloco.colunas || []).length;

    const headerColunas = (bloco.colunas || []).map((c, i) => {
      const radius = i === 0 ? '0' : (i === nCols - 1 ? '0 12px 0 0' : '0');
      return `<th style="text-align:center; padding:18px 22px; font-size:13px; font-weight:700; letter-spacing:2px; color:${NAVY}; background:${CARD_BG}; border-radius:${radius};">${c}</th>`;
    }).join(sep ? `<th style="width:60px; background:${CARD_BG};"></th>` : '');

    const linhasHtml = (bloco.linhas || []).map((linha, iL) => {
      const isLast = iL === bloco.linhas.length - 1;
      const borderBottom = isLast ? 'none' : `1px solid ${BORDER}`;
      const cellLabel = `<td style="padding:16px 22px; color:${TEXT_MUTED}; font-size:16px; border-bottom:${borderBottom};">${linha.label}</td>`;
      const cellsValores = (linha.valores || []).map((v, iV) => {
        let html = `<td style="padding:16px 22px; text-align:center; font-weight:700; font-size:18px; border-bottom:${borderBottom};">${v}</td>`;
        // separador "OU" no meio (rowspan na primeira linha)
        if (sep && iV === 0 && (bloco.valores || bloco.linhas).length > 1 && nCols === 2 && iL === 0) {
          html += `<td rowspan="${bloco.linhas.length}" style="text-align:center; color:${TEXT_MUTED}; font-weight:600; font-size:14px;">${sep}</td>`;
        }
        return html;
      }).join('');
      return `<tr>${cellLabel}${cellsValores}</tr>`;
    }).join('');

    return `
      <table style="width:100%; border-collapse:separate; border-spacing:0; margin-top:32px;">
        <thead>
          <tr>
            <th style="text-align:left; padding:18px 22px; font-size:13px; font-weight:700; letter-spacing:2px; color:${NAVY}; background:${CARD_BG}; border-radius:12px 0 0 0;">${bloco.titulo}</th>
            ${headerColunas}
          </tr>
        </thead>
        <tbody>${linhasHtml}</tbody>
      </table>`;
  }

  // ─── BLOCO TIPO "TEXTO" (livre, ex: observações) ───
  function renderTexto(bloco) {
    return `
      ${bloco.titulo ? `<div style="font-size:14px; font-weight:700; letter-spacing:2.5px; color:${NAVY}; margin:28px 0 16px;">${bloco.titulo}</div>` : ''}
      <div style="font-size:15px; color:#1F2937; line-height:1.55;">${bloco.html || bloco.texto || ''}</div>`;
  }

  // ─── BLOCO TIPO "TABELA-AMPLA" ───
  // Tabela com N colunas (3-11) e linha "Total" opcional destacada.
  // Usado em "Consórcio como Investimento" e "Operação Estruturada".
  // {
  //   tipo: 'tabela-ampla',
  //   titulo: '...' (opcional),
  //   colunas: ['#', 'CRÉDITO CONTRATADO', '1ª PARCELA', ...],
  //   linhas: [
  //     { celulas: ['1', 'R$ 6.300.000,00', ...] },
  //     { celulas: ['Total', 'R$ 6.300.000,00', ...], total: true }
  //   ],
  //   compact: false  // se true, reduz padding/font para caber muitas colunas
  // }
  function renderTabelaAmpla(bloco) {
    const compact = !!bloco.compact || (bloco.colunas || []).length >= 9;
    const padCell = compact ? '12px 10px' : '16px 14px';
    const fontHeader = compact ? '11px' : '12px';
    const fontCell = compact ? '13px' : '14px';

    const headHtml = (bloco.colunas || []).map((c, i) => `
      <th style="padding:${padCell}; font-size:${fontHeader}; font-weight:700; letter-spacing:1.2px; color:${NAVY}; text-align:${i === 0 ? 'left' : 'center'}; border-bottom:2px solid ${BORDER}; vertical-align:middle;">${c}</th>
    `).join('');

    const linhasHtml = (bloco.linhas || []).map((linha, iL) => {
      const isTotal = !!linha.total;
      const bg = isTotal ? CARD_BG : (iL % 2 === 1 ? ZEBRA : '#fff');
      const fontWeight = isTotal ? '700' : '500';
      const cellsHtml = (linha.celulas || []).map((v, iV) => `
        <td style="padding:${padCell}; font-size:${fontCell}; font-weight:${fontWeight}; color:#1F2937; text-align:${iV === 0 ? 'left' : 'center'}; vertical-align:middle;">${v == null ? '' : v}</td>
      `).join('');
      return `<tr style="background:${bg};">${cellsHtml}</tr>`;
    }).join('');

    return `
      ${bloco.titulo ? `<div style="font-size:14px; font-weight:700; letter-spacing:2.5px; color:${NAVY}; margin:28px 0 16px;">${bloco.titulo}</div>` : '<div style="margin-top:24px;"></div>'}
      <table style="width:100%; border-collapse:collapse; border-spacing:0; border:1px solid ${BORDER}; border-radius:8px; overflow:hidden;">
        <thead><tr style="background:${CARD_BG};">${headHtml}</tr></thead>
        <tbody>${linhasHtml}</tbody>
      </table>`;
  }

  // ─── BLOCO TIPO "TABELA-SECAO" ───
  // Tabela com header roxo de seção + linhas label/valor1/valor2 (compara dois cenários
  // lado a lado, ex: Cota A vs Cota B). Usado em "Consórcio X Consórcio".
  // {
  //   tipo: 'tabela-secao',
  //   titulo: 'DETALHES DA PROPOSTA',
  //   linhas: [
  //     { label: 'Crédito', valores: ['R$ 100.000,00', 'R$ 0,00'] },
  //     { label: 'Custo efetivo', valores: ['0,29 % ao mês', '0 % ao mês'], destaque: true }
  //   ]
  // }
  function renderTabelaSecao(bloco) {
    const linhasHtml = (bloco.linhas || []).map((linha, iL) => {
      const bg = iL % 2 === 1 ? ZEBRA : '#fff';
      const valoresHtml = (linha.valores || []).map(v => {
        const cellBg = linha.destaque ? PURPLE_LIGHT : 'transparent';
        return `<td style="padding:14px 22px; text-align:center; font-size:15px; color:#1F2937; background:${cellBg}; border-radius:${linha.destaque ? '20px' : '0'};">${v == null || v === '' ? '-' : v}</td>`;
      }).join('');
      return `
        <tr style="background:${bg}; border-bottom:1px solid ${BORDER};">
          <td style="padding:14px 22px; color:#374151; font-size:15px; font-weight:500; width:38%;">${linha.label}</td>
          ${valoresHtml}
        </tr>`;
    }).join('');

    const colSpan = ((bloco.linhas && bloco.linhas[0] && bloco.linhas[0].valores) || []).length + 1;

    return `
      <table style="width:100%; border-collapse:separate; border-spacing:0; margin-top:24px; border:1px solid ${BORDER}; border-radius:8px; overflow:hidden;">
        <thead>
          <tr>
            <th colspan="${colSpan}" style="background:${NAVY}; color:#fff; padding:14px 22px; text-align:left; font-size:13px; font-weight:700; letter-spacing:1.5px;">${bloco.titulo || ''}</th>
          </tr>
        </thead>
        <tbody>${linhasHtml}</tbody>
      </table>`;
  }

  // ─── BLOCO TIPO "CARDS-ICONE" ───
  // Faixa horizontal de mini-cards (ícone + label + valor). Último pode ser destacado.
  // Usado em "Consórcio como Investimento".
  // {
  //   tipo: 'cards-icone',
  //   items: [
  //     { icone: 'cifrao', label: 'Venda da cota', valor: 'R$ 0,00' },
  //     { icone: 'predio', label: 'Imóveis alugados', valor: 'R$ ...' },
  //     { icone: 'banco', label: 'Patrimônio Total', valor: 'R$ ...', destaque: true }
  //   ]
  // }
  const ICONES = {
    cifrao:  '<circle cx="12" cy="12" r="9" fill="none" stroke="currentColor" stroke-width="1.6"/><text x="12" y="16" font-size="12" font-weight="700" text-anchor="middle" fill="currentColor">$</text>',
    predio:  '<rect x="5" y="4" width="14" height="16" rx="1" fill="none" stroke="currentColor" stroke-width="1.6"/><line x1="9" y1="8" x2="9" y2="9" stroke="currentColor" stroke-width="1.6"/><line x1="15" y1="8" x2="15" y2="9" stroke="currentColor" stroke-width="1.6"/><line x1="9" y1="12" x2="9" y2="13" stroke="currentColor" stroke-width="1.6"/><line x1="15" y1="12" x2="15" y2="13" stroke="currentColor" stroke-width="1.6"/><line x1="9" y1="16" x2="9" y2="17" stroke="currentColor" stroke-width="1.6"/><line x1="15" y1="16" x2="15" y2="17" stroke="currentColor" stroke-width="1.6"/>',
    venda:   '<circle cx="12" cy="12" r="9" fill="none" stroke="currentColor" stroke-width="1.6"/><path d="M9 12 L12 15 L16 9" stroke="currentColor" stroke-width="1.6" fill="none" stroke-linecap="round"/>',
    piggy:   '<path d="M4 13 c0 -3 3 -6 8 -6 c5 0 8 3 8 6 c0 1 -1 2 -2 2 v3 h-3 v-2 h-6 v2 h-3 v-3 c-1 0 -2 -1 -2 -2 z" fill="none" stroke="currentColor" stroke-width="1.6"/><circle cx="9" cy="12" r="0.8" fill="currentColor"/>',
    banco:   '<polygon points="3,9 12,4 21,9 21,11 3,11" fill="none" stroke="currentColor" stroke-width="1.6"/><line x1="6" y1="11" x2="6" y2="17" stroke="currentColor" stroke-width="1.6"/><line x1="10" y1="11" x2="10" y2="17" stroke="currentColor" stroke-width="1.6"/><line x1="14" y1="11" x2="14" y2="17" stroke="currentColor" stroke-width="1.6"/><line x1="18" y1="11" x2="18" y2="17" stroke="currentColor" stroke-width="1.6"/><line x1="3" y1="19" x2="21" y2="19" stroke="currentColor" stroke-width="1.6"/>',
    pessoa:  '<circle cx="12" cy="8" r="3" fill="none" stroke="currentColor" stroke-width="1.6"/><path d="M5 20 c0 -4 3 -7 7 -7 c4 0 7 3 7 7" fill="none" stroke="currentColor" stroke-width="1.6"/>'
  };

  function renderIcone(nome, cor) {
    const path = ICONES[nome] || ICONES.cifrao;
    return `<svg width="22" height="22" viewBox="0 0 24 24" style="color:${cor}; flex-shrink:0;" xmlns="http://www.w3.org/2000/svg">${path}</svg>`;
  }

  function renderCardsIcone(bloco) {
    const items = bloco.items || [];
    const itemsHtml = items.map(item => {
      const isDestaque = !!item.destaque;
      const bg = isDestaque ? PURPLE_LIGHT : CARD_BG;
      const corIcon = isDestaque ? NAVY : NAVY;
      const borderLeft = isDestaque ? `border-left:4px solid ${PURPLE_BORDER};` : '';
      return `
        <div style="flex:1; min-width:0; background:${bg}; border-radius:10px; padding:18px 20px; ${borderLeft}">
          <div style="display:flex; align-items:center; gap:10px; margin-bottom:8px;">
            ${renderIcone(item.icone, corIcon)}
            <div style="font-size:13px; color:${TEXT_MUTED}; font-weight:500;">${item.label}</div>
          </div>
          <div style="font-size:18px; font-weight:700; color:#1F2937;">${item.valor}</div>
        </div>`;
    }).join('');

    return `
      ${bloco.titulo ? `<div style="font-size:14px; font-weight:700; letter-spacing:2.5px; color:${NAVY}; margin:28px 0 16px;">${bloco.titulo}</div>` : '<div style="margin-top:20px;"></div>'}
      <div style="display:flex; gap:14px; align-items:stretch;">${itemsHtml}</div>`;
  }

  // ─── BLOCO TIPO "LISTA-PONTILHADA" ───
  // Lista vertical estilo "label .................. valor" com sub-bullets indentados.
  // Usada em "Consórcio X À Vista" (RESULTADO).
  // {
  //   tipo: 'lista-pontilhada',
  //   titulo: 'RESULTADO',
  //   linhas: [
  //     { label: 'Fazendo à vista', icone: 'pessoa', sufixo: '(Somente bem valorizado)', valor: 'R$ 982.781,99', destaque: true },
  //     { label: 'Fazendo com consórcio', valor: 'R$ 1.102.391,19', bold: true },
  //     { label: 'Bem valorizado', valor: 'R$ 982.781,99', sub: true },
  //     { label: 'Custo do lance', valor: 'SACADO DO INVESTIMENTO', sub: true }
  //   ]
  // }
  function renderListaPontilhada(bloco) {
    const linhasHtml = (bloco.linhas || []).map(linha => {
      const indent = linha.sub ? '24px' : '0';
      const fontWeight = linha.bold || linha.destaque ? '700' : '500';
      const corLabel = linha.destaque ? NAVY : (linha.sub ? '#374151' : '#1F2937');
      const corValor = linha.destaque ? NAVY : '#1F2937';
      const bullet = linha.sub ? '<span style="color:#9CA3AF; margin-right:8px;">•</span>' : '';
      const iconeHtml = linha.icone ? `<span style="margin-right:8px;">${renderIcone(linha.icone, NAVY)}</span>` : '';
      const sufixoHtml = linha.sufixo ? `<span style="color:${TEXT_MUTED}; font-weight:500; font-size:14px; margin-right:6px;">${linha.sufixo}</span>` : '';

      return `
        <div style="display:flex; align-items:center; padding:8px 0; padding-left:${indent}; border-bottom:1px dotted ${BORDER};">
          <div style="display:flex; align-items:center; flex-shrink:0;">
            ${bullet}${iconeHtml}
            <span style="font-size:15px; font-weight:${fontWeight}; color:${corLabel};">${linha.label}</span>
          </div>
          <div style="flex:1; border-bottom:2px dotted ${BORDER}; margin:0 12px; height:1px; align-self:flex-end; margin-bottom:6px;"></div>
          <div style="flex-shrink:0; text-align:right;">
            ${sufixoHtml}<span style="font-size:15px; font-weight:${fontWeight}; color:${corValor};">${linha.valor}</span>
          </div>
        </div>`;
    }).join('');

    return `
      ${bloco.titulo ? `<div style="font-size:14px; font-weight:700; letter-spacing:2.5px; color:${NAVY}; margin:28px 0 12px;">${bloco.titulo}</div>` : ''}
      <div>${linhasHtml}</div>`;
  }

  // ─── BLOCO TIPO "CARDS-COMPARATIVOS" ───
  // 2 cards lado a lado (verde + cinza) com lista pontilhada + linha de fechamento.
  // Usado em "Consórcio X Financiamento" (RESULTADO DO COMPARATIVO).
  // {
  //   tipo: 'cards-comparativos',
  //   titulo: 'RESULTADO DO COMPARATIVO: CONSÓRCIO X FINANCIAMENTO',
  //   cards: [
  //     { titulo: 'Consórcio', cor: 'verde', icone: 'pessoa', linhas: [
  //         { label: 'Custo da operação', valor: 'R$ 508.228,04' },
  //         { label: 'Parcela pós-contemplação', valor: 'R$ 3.351,11' }
  //     ]},
  //     { titulo: 'Financiamento', cor: 'cinza', linhas: [...] }
  //   ],
  //   separador: 'X',  // opcional
  //   fechamento: { label: 'Economia fazendo por consórcio:', valor: 'R$ 602.528,34' }
  // }
  function renderCardsComparativos(bloco) {
    const cards = (bloco.cards || []).slice(0, 2);
    const sep = bloco.separador || 'X';

    const cardHtml = cards.map(card => {
      const isVerde = card.cor === 'verde';
      const bg = isVerde ? GREEN_BG : GRAY_BG;
      const corTitulo = isVerde ? GREEN_DARK : NAVY;
      const linhasHtml = (card.linhas || []).map(linha => `
        <div style="display:flex; align-items:flex-end; padding:6px 0;">
          <span style="font-size:14px; color:#374151;">${linha.label}</span>
          <span style="flex:1; border-bottom:1px dotted ${BORDER}; margin:0 8px; height:1px; margin-bottom:5px;"></span>
          <span style="font-size:15px; font-weight:700; color:#1F2937;">${linha.valor}</span>
        </div>`).join('');

      return `
        <div style="flex:1; background:${bg}; border-radius:10px; padding:20px 24px;">
          <div style="display:flex; align-items:center; gap:8px; margin-bottom:14px;">
            ${card.icone ? renderIcone(card.icone, corTitulo) : ''}
            <div style="font-size:16px; font-weight:700; color:${corTitulo};">${card.titulo}</div>
          </div>
          <div>${linhasHtml}</div>
        </div>`;
    }).join(`<div style="display:flex; align-items:center; padding:0 14px; font-size:18px; font-weight:600; color:${TEXT_MUTED};">${sep}</div>`);

    let fechamentoHtml = '';
    if (bloco.fechamento) {
      fechamentoHtml = `
        <div style="margin-top:18px; background:${GREEN_BG}; border-radius:10px; padding:16px 24px; display:flex; justify-content:space-between; align-items:center;">
          <div style="font-size:15px; font-weight:700; color:${GREEN_DARK};">${bloco.fechamento.label}</div>
          <div style="font-size:18px; font-weight:700; color:${GREEN_DARK};">${bloco.fechamento.valor}</div>
        </div>`;
    }

    return `
      ${bloco.titulo ? `<div style="font-size:14px; font-weight:700; letter-spacing:2.5px; color:${NAVY}; margin:28px 0 16px;">${bloco.titulo}</div>` : ''}
      <div style="display:flex; align-items:stretch;">${cardHtml}</div>
      ${fechamentoHtml}`;
  }

  // ─── BLOCO TIPO "RESULTADO-SECAO" ───
  // Header roxo grande + linhas label/valor com zebra striping.
  // Usado em "Operação Estruturada" (RESULTADO).
  // {
  //   tipo: 'resultado-secao',
  //   titulo: 'RESULTADO',
  //   linhas: [
  //     { label: 'Crédito total contratado', valor: 'R$ 6.300.000,00' },
  //     { label: 'Lance total', valor: '(30%) R$ 1.890.000,00' },
  //     { label: 'CET (Custo Efetivo Total)', valor: '0,25% ao mês | 3,04% ao ano' }
  //   ]
  // }
  function renderResultadoSecao(bloco) {
    const linhasHtml = (bloco.linhas || []).map((linha, iL) => {
      const bg = iL % 2 === 0 ? ZEBRA : '#fff';
      return `
        <tr style="background:${bg};">
          <td style="padding:18px 26px; font-size:16px; color:#374151; border-right:1px solid ${BORDER}; width:60%;">${linha.label}</td>
          <td style="padding:18px 26px; font-size:18px; font-weight:700; color:#1F2937; text-align:right;">${linha.valor}</td>
        </tr>`;
    }).join('');

    return `
      <table style="width:100%; border-collapse:separate; border-spacing:0; margin-top:28px; border:1px solid ${BORDER}; border-radius:10px; overflow:hidden;">
        <thead>
          <tr>
            <th colspan="2" style="background:${NAVY}; color:#fff; padding:18px 26px; text-align:left; font-size:14px; font-weight:700; letter-spacing:2px;">${bloco.titulo || 'RESULTADO'}</th>
          </tr>
        </thead>
        <tbody>${linhasHtml}</tbody>
      </table>`;
  }

  // ─── DISCLAIMER ───
  function renderDisclaimer(linhas) {
    const paragrafos = (linhas || DISCLAIMER_PADRAO);
    return `
      <div style="margin-top:36px; font-size:13px; color:${TEXT_MUTED}; line-height:1.65; text-align:justify;">
        ${paragrafos.map(p => `<p style="margin:0 0 12px;">${p}</p>`).join('')}
      </div>`;
  }

  // ─── BUILD TEMPLATE COMPLETO ───
  function buildTemplate(opts) {
    const blocosHtml = (opts.blocos || []).map(b => {
      if (b.tipo === 'card') return renderCard(b);
      if (b.tipo === 'tabela') return renderTabela(b);
      if (b.tipo === 'texto') return renderTexto(b);
      if (b.tipo === 'tabela-ampla') return renderTabelaAmpla(b);
      if (b.tipo === 'tabela-secao') return renderTabelaSecao(b);
      if (b.tipo === 'cards-icone') return renderCardsIcone(b);
      if (b.tipo === 'lista-pontilhada') return renderListaPontilhada(b);
      if (b.tipo === 'cards-comparativos') return renderCardsComparativos(b);
      if (b.tipo === 'resultado-secao') return renderResultadoSecao(b);
      return '';
    }).join('');

    return `
      <div style="width:1300px; background:#fff; font-family:'Inter',-apple-system,system-ui,sans-serif; color:#1F2937; font-size:18px; line-height:1.5;">
        ${renderHeader(opts.tituloEstrategia)}
        <div style="padding:42px 50px;">
          ${blocosHtml}
          ${renderDisclaimer(opts.disclaimer)}
        </div>
        ${renderFooter()}
      </div>`;
  }

  // ─── GERA O PDF (html2canvas + jsPDF, escala pra A4) ───
  async function gerar(opts) {
    if (typeof html2canvas !== 'function') throw new Error('html2canvas não está carregado');
    if (!window.jspdf || !window.jspdf.jsPDF) throw new Error('jsPDF não está carregado');

    // Cria container off-screen mas dentro da viewport (z-index baixíssimo)
    const wrap = document.createElement('div');
    wrap.style.cssText = `position:fixed; top:0; left:0; width:${PDF_WIDTH}px; background:#fff; z-index:-99999; pointer-events:none; overflow:hidden;`;
    wrap.innerHTML = buildTemplate(opts);
    document.body.appendChild(wrap);

    try {
      // Aguarda layout + carregamento de imagens (logo SVG é inline, mas dá uma folga)
      await new Promise(r => setTimeout(r, 350));

      const target = wrap.firstElementChild;
      const canvas = await html2canvas(target, {
        scale: 2,
        backgroundColor: '#FFFFFF',
        width: PDF_WIDTH,
        windowWidth: PDF_WIDTH,
        useCORS: true,
        allowTaint: true,
        logging: false
      });

      const { jsPDF } = window.jspdf;
      const pdf = new jsPDF({ unit: 'mm', format: 'a4', orientation: 'portrait', compress: true });
      const pageW = 210, pageH = 297;
      const fitW = pageW;
      const fitH = (canvas.height * fitW) / canvas.width;
      const imgData = canvas.toDataURL('image/jpeg', 0.96);

      if (fitH <= pageH) {
        pdf.addImage(imgData, 'JPEG', 0, 0, fitW, fitH);
      } else {
        // Conteúdo maior que A4 — escala pra caber em 1 página inteira
        const fitH2 = pageH;
        const fitW2 = (canvas.width * fitH2) / canvas.height;
        const offsetX = (pageW - fitW2) / 2;
        pdf.addImage(imgData, 'JPEG', offsetX, 0, fitW2, fitH2);
      }

      const hoje = new Date();
      const dd = String(hoje.getDate()).padStart(2, '0');
      const mm = String(hoje.getMonth() + 1).padStart(2, '0');
      const yyyy = hoje.getFullYear();
      const filename = (opts.filename || 'master-prime-simulacao') + `-${dd}${mm}${yyyy}.pdf`;
      pdf.save(filename);
    } finally {
      wrap.remove();
    }
  }

  // ─── PREVIEW INLINE (para validar visualmente sem baixar) ───
  function preview(opts) {
    // Esconde o conteúdo normal da página (header + main do simulador)
    document.querySelectorAll('header, main').forEach(el => el.style.display = 'none');

    const wrap = document.createElement('div');
    wrap.style.cssText = 'min-height:100vh; background:#E5E7EB; padding:40px 0; display:flex; flex-direction:column; align-items:center; gap:24px; font-family:Inter,sans-serif;';
    wrap.innerHTML = `
      <div style="text-align:center;">
        <div style="color:${NAVY_DARK}; font-size:14px; letter-spacing:1.5px; text-transform:uppercase; font-weight:700;">Pré-visualização do PDF — Master Prime · ${opts.tituloEstrategia}</div>
        <div style="color:${TEXT_MUTED}; font-size:12px; margin-top:4px;">Cenário demo · escala 1:1 (1300px)</div>
      </div>
      <div style="box-shadow:0 12px 40px rgba(0,0,0,0.12); border-radius:6px; overflow:hidden;">
        ${buildTemplate(opts)}
      </div>`;
    document.body.appendChild(wrap);
  }

  // ─── EXPORT PUBLIC API ───
  window.PdfMasterPrime = { gerar, preview, buildTemplate, _internals: { DISCLAIMER_PADRAO, NAVY, CARD_BG } };
})();
